import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './components/Login';
import Register from './components/Register';
import Dashboard from './components/Dashboard';
import Predictor from './components/Predictor';
import './App.css';

const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return <div>Loading...</div>;
  return user ? children : <Navigate to="/login" />;
};

const AppContent = () => {
  return (
    <Router>
      <div className="App">
        <header>
          <h1>🎓 Student Performance AI System</h1>
          <nav style={{ color: 'white', fontSize: '1.1rem' }}>
            <Link to="/predictor" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Predictor</Link> | 
            <Link to="/dashboard" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Dashboard</Link> | 
            <Link to="/login" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Login</Link> | 
            <Link to="/register" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Register</Link>
          </nav>
        </header>
        <Routes>
          <Route path="/" element={<Navigate to="/predictor" />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/predictor" element={<Predictor />} />
          <Route path="/dashboard" element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } />
        </Routes>
      </div>
    </Router>
  );
};

const App = () => (
  <AuthProvider>
    <AppContent />
  </AuthProvider>
);

export default App;
